const spendData = $('Fetch Today Spend').first().json;
const adsData = $('Fetch Active Ads').first().json;

const stats = spendData.data || spendData;
const ads = adsData.data || adsData;

const dailyBudget = parseFloat($env.DAILY_BUDGET_LIMIT || '50');
const maxCeiling = parseFloat($env.MAX_BID_CEILING || '0.10');

// Calculate total spend today
let totalSpend = 0;
if (Array.isArray(stats)) {
  stats.forEach(s => { totalSpend += parseFloat(s.money) || 0; });
} else if (stats.money) {
  totalSpend = parseFloat(stats.money) || 0;
}

const now = new Date();
const hoursElapsed = now.getHours() + now.getMinutes() / 60;
const hoursRemaining = 24 - hoursElapsed;
const remainingBudget = dailyBudget - totalSpend;

// Target spend rate
const targetSpendPerHour = hoursRemaining > 0 ? remainingBudget / hoursRemaining : 0;
const actualSpendPerHour = hoursElapsed > 0 ? totalSpend / hoursElapsed : 0;

let action = 'HOLD';
let bidAdjustment = 1.0;
let reason = '';

// Overspending: spending 20% more than target
if (actualSpendPerHour > targetSpendPerHour * 1.2 && totalSpend > dailyBudget * 0.3) {
  action = 'LOWER_ALL';
  bidAdjustment = 0.90;
  reason = `Overspending: $${actualSpendPerHour.toFixed(2)}/h vs target $${targetSpendPerHour.toFixed(2)}/h`;
}
// Underspending: spending 30% less than target, and we have budget to use
else if (actualSpendPerHour < targetSpendPerHour * 0.7 && remainingBudget > dailyBudget * 0.3 && hoursElapsed > 4) {
  action = 'RAISE_ALL';
  bidAdjustment = 1.10;
  reason = `Underspending: $${actualSpendPerHour.toFixed(2)}/h vs target $${targetSpendPerHour.toFixed(2)}/h`;
}
// Budget nearly exhausted
else if (remainingBudget < dailyBudget * 0.1 && hoursRemaining > 4) {
  action = 'LOWER_ALL';
  bidAdjustment = 0.80;
  reason = `Budget nearly exhausted: $${remainingBudget.toFixed(2)} left for ${hoursRemaining.toFixed(1)}h`;
}

if (action === 'HOLD') {
  return [{ json: { action: 'HOLD', reason: 'Budget pacing is on track', totalSpend, dailyBudget, actualSpendPerHour, targetSpendPerHour } }];
}

// Prepare bid updates for all active ads
const bidUpdates = [];
if (Array.isArray(ads)) {
  ads.forEach(ad => {
    const currentBid = parseFloat(ad.one_bid_for_all_geo) || 0;
    let newBid = currentBid * bidAdjustment;
    if (newBid > maxCeiling) newBid = maxCeiling;
    if (newBid < 0.001) newBid = 0.001;
    bidUpdates.push({
      ad_id: ad.id,
      one_bid_for_all_geo: Math.round(newBid * 10000) / 10000
    });
  });
}

return [{
  json: {
    action: action,
    reason: reason,
    bid_adjustment: bidAdjustment,
    total_spend: Math.round(totalSpend * 100) / 100,
    daily_budget: dailyBudget,
    remaining_budget: Math.round(remainingBudget * 100) / 100,
    actual_rate: Math.round(actualSpendPerHour * 100) / 100,
    target_rate: Math.round(targetSpendPerHour * 100) / 100,
    ads_to_update: bidUpdates
  }
}];

